const a = $json.body || $json;
const required = ['proposal_id','agent','action_type','payload','created_at','tenant'];
for (const k of required) {
  if (!(k in a)) throw new Error('ProposedAction missing field: ' + k);
}
const allowed = ['email.send','crm.update_record','ticket.create','db.update_row','api.call','n8n.trigger_workflow'];
if (!allowed.includes(a.action_type)) throw new Error('Unknown action_type: ' + a.action_type);
if (a.expires_at && new Date(a.expires_at) < new Date()) throw new Error('Proposal already expired');
return [{json: a}];

